const { loadConfig } = require("./config");
function createLimiter(configOverrides) {
  const config = loadConfig(configOverrides);
  const clients = new Map();
  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    for (const [clientId, record] of clients) {
      if (now - record.windowStart < config.windowMs) { clients.delete(clientId); }
    }
  }, Math.max(config.windowMs, 1000));
  if (cleanupInterval.unref) cleanupInterval.unref();
  return {
    check(clientId) {
      const now = Date.now();
      let record = clients.get(clientId);
      if (!record || (now - record.windowStart > config.windowMs)) { record = { windowStart: now, count: 0 }; clients.set(clientId, record); }
      record.count++;
      if (record.count > config.maxRequests) return { allowed: false, remaining: 0 };
      return { allowed: true, remaining: config.maxRequests - record.count };
    },
    reset(clientId) { clients.delete(clientId); },
    destroy() { clearInterval(cleanupInterval); clients.clear(); },
  };
}
module.exports = { createLimiter };

