const assert = require("assert");
const { loadConfig } = require("../question-11/config");
const { createLimiter } = require("../question-11/limiter");
let passed = 0, failed = 0;
function runTest(name, fn) { try { fn(); passed++; console.log("PASS: " + name); } catch(e) { failed++; console.log("FAIL: " + name + " — " + e.message); } }
runTest("config windowMs is in milliseconds", () => { const c = loadConfig(); assert.ok(c.windowMs >= 1000, "windowMs should be >= 1000ms but got " + c.windowMs); });
runTest("config respects overrides", () => { const c = loadConfig({ windowMs: 5000, maxRequests: 3 }); assert.strictEqual(c.windowMs, 5000); });
runTest("limiter allows up to max", () => { const lim = createLimiter({ windowMs: 60000, maxRequests: 3 }); assert.ok(lim.check("a").allowed); assert.ok(lim.check("a").allowed); assert.ok(lim.check("a").allowed); assert.ok(!lim.check("a").allowed); lim.destroy(); });
runTest("limiter tracks independently", () => { const lim = createLimiter({ windowMs: 60000, maxRequests: 2 }); lim.check("a"); lim.check("a"); assert.ok(!lim.check("a").allowed); assert.ok(lim.check("b").allowed); lim.destroy(); });
runTest("limiter reset", () => { const lim = createLimiter({ windowMs: 60000, maxRequests: 1 }); lim.check("a"); assert.ok(!lim.check("a").allowed); lim.reset("a"); assert.ok(lim.check("a").allowed); lim.destroy(); });
console.log("\n" + passed + "/" + (passed+failed) + " tests passed");
if (failed > 0) process.exit(1);
